#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int n, shift;
    if (scanf("%d", &n) != 1) return 0;
    if (n < 1 || n > 1000) return 0;

    int *a = (int *)malloc((size_t)n * sizeof(int));
    if (!a) return 0;

    for (int i = 0; i < n; i++) {
        if (scanf("%d", &a[i]) != 1) {
            free(a);
            return 0;
        }
    }
    if (scanf("%d", &shift) != 1) {
        free(a);
        return 0;
    }

    long long sum = 0;
    for (int i = 0; i < n; i++) {
        sum += (long long)a[i] + shift;
    }

    printf("%.2f\n", (double)sum / n);
    free(a);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int n;
    if (scanf("%d", &n) != 1) return 0;
    if (n < 1 || n > 1000) return 0;

    int *a = (int *)malloc((size_t)n * sizeof(int));
    if (!a) return 0;

    for (int i = 0; i < n; i++) {
        if (scanf("%d", &a[i]) != 1) {
            free(a);
            return 0;
        }
    }

    int first = 1;
    for (int i = n - 1; i >= 0; i--) {
        if (a[i] >= 0) {
            if (!first) printf(" ");
            printf("%d", a[i]);
            first = 0;
        }
    }

    if (first) printf("0");
    printf("\n");

    free(a);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <ctype.h>

int main(void) {
    char buffer[256];
    if (!fgets(buffer, sizeof(buffer), stdin)) return 0;

    size_t len = strlen(buffer);
    while (len > 0 && (buffer[len - 1] == '\n' || buffer[len - 1] == '\r')) {
        buffer[--len] = '\0';
    }

    char *line = (char *)malloc(len + 1);
    if (!line) return 0;
    strcpy(line, buffer);

    int words = 0;
    int letters = 0;
    int in_word = 0;

    for (char *p = line; *p != '\0'; p++) {
        if (*p != ' ') {
            letters++;
            if (!in_word) {
                words++;
                in_word = 1;
            }
        } else {
            in_word = 0;
        }
    }

    printf("%d %d\n", words, letters);

    free(line);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int *a = NULL;
    int count = 0;
    int x;

    while (scanf("%d", &x) == 1) {
        if (x == -1) break;
        int *tmp = (int *)realloc(a, (size_t)(count + 1) * sizeof(int));
        if (!tmp) {
            free(a);
            return 0;
        }
        a = tmp;
        a[count++] = x;
    }

    if (count == 0) {
        printf("0\n");
        free(a);
        return 0;
    }

    long long sum = 0;
    for (int i = 0; i < count; i++) {
        sum += a[i];
        if (i > 0) printf(" ");
        printf("%lld", sum);
    }
    printf("\n");

    free(a);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <ctype.h>

int main(void) {
    char buffer[256];
    if (!fgets(buffer, sizeof(buffer), stdin)) return 0;

    size_t len = strlen(buffer);
    while (len > 0 && (buffer[len - 1] == '\n' || buffer[len - 1] == '\r')) {
        buffer[--len] = '\0';
    }

    char *s = (char *)malloc(len + 1);
    if (!s) return 0;
    strcpy(s, buffer);

    int upper = 0, lower = 0, digit = 0, other = 0;
    for (char *p = s; *p != '\0'; p++) {
        if (isupper((unsigned char)*p)) upper++;
        else if (islower((unsigned char)*p)) lower++;
        else if (isdigit((unsigned char)*p)) digit++;
        else other++;
    }

    printf("%d %d %d %d\n", upper, lower, digit, other);

    free(s);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int n;
    if (scanf("%d", &n) != 1) return 0;
    if (n < 1 || n > 1000) return 0;

    int *in = (int *)malloc((size_t)n * sizeof(int));
    if (!in) return 0;

    for (int i = 0; i < n; i++) {
        if (scanf("%d", &in[i]) != 1) {
            free(in);
            return 0;
        }
    }

    int out_size = 0;
    for (int i = 0; i < n; i++) out_size += (in[i] > 0) ? 2 : 1;

    int *out = (int *)malloc((size_t)out_size * sizeof(int));
    if (!out) {
        free(in);
        return 0;
    }

    int k = 0;
    for (int i = 0; i < n; i++) {
        out[k++] = in[i];
        if (in[i] > 0) out[k++] = in[i];
    }

    for (int i = 0; i < out_size; i++) {
        if (i > 0) printf(" ");
        printf("%d", out[i]);
    }
    printf("\n");

    free(in);
    free(out);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main(void) {
    int n;
    if (scanf("%d", &n) != 1) return 0;
    if (n < 3 || n > 1000) return 0;

    int *a = (int *)malloc((size_t)n * sizeof(int));
    if (!a) return 0;

    for (int i = 0; i < n; i++) {
        if (scanf("%d", &a[i]) != 1) {
            free(a);
            return 0;
        }
    }

    int mn = a[1], mx = a[1];
    for (int i = 2; i <= n - 2; i++) {
        if (a[i] < mn) mn = a[i];
        if (a[i] > mx) mx = a[i];
    }

    printf("%d %d\n", mn, mx);
    free(a);
    return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main(void) {
    char buffer[256];
    if (!fgets(buffer, sizeof(buffer), stdin)) return 0;

    size_t len = strlen(buffer);
    while (len > 0 && (buffer[len - 1] == '\n' || buffer[len - 1] == '\r')) {
        buffer[--len] = '\0';
    }

    char *s = (char *)malloc(len + 1);
    if (!s) return 0;
    strcpy(s, buffer);

    char *out = (char *)malloc(len + 1);
    if (!out) {
        free(s);
        return 0;
    }

    size_t k = 0;
    if (len > 0) {
        out[k++] = s[0];
        for (size_t i = 1; i < len; i++) {
            if (s[i] != s[i - 1]) out[k++] = s[i];
        }
    }
    out[k] = '\0';

    printf("%s\n", out);

    free(s);
    free(out);
    return 0;
}

