#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <ctype.h>

int main(void) {
    char buffer[256];
    if (!fgets(buffer, sizeof(buffer), stdin)) return 0;

    size_t len = strlen(buffer);
    while (len > 0 && (buffer[len - 1] == '\n' || buffer[len - 1] == '\r')) {
        buffer[--len] = '\0';
    }

    char *s = (char *)malloc(len + 1);
    if (!s) return 0;
    strcpy(s, buffer);

    char first = '\0', last = '\0';
    for (char *p = s; *p != '\0'; p++) {
        if (isalpha((unsigned char)*p)) {
            if (first == '\0') first = *p;
            last = *p;
        }
    }

    if (first == '\0') {
        printf("NONE\n");
    } else {
        printf("%c %c\n", first, last);
    }

    free(s);
    return 0;
}
